// ========== 登录验证 ==========
static int validate_login_inputs(const char *phone, const char *password, const char *code, char *err_msg, int err_size)
{
    // 1. 验证账号（电话号码）
    if(!phone || strlen(phone) == 0) {
        snprintf(err_msg, err_size, "请输入电话号码");
        return -1;
    }
    if(!is_valid_phone(phone)) {
        snprintf(err_msg, err_size, "电话号码必须为11位数字");
        return -2;
    }
    
    // 2. 验证密码
    if(!password || strlen(password) == 0) {
        snprintf(err_msg, err_size, "请输入密码");
        return -3;
    }
    
    // 3. 验证验证码
    if(!code || strlen(code) == 0) {
        snprintf(err_msg, err_size, "请输入验证码");
        return -4;
    }
    if(!verify_code(code)) {
        snprintf(err_msg, err_size, "验证码错误");
        return -5;
    }
    
    // 4. 检查账号是否存在
    int idx = find_user_by_phone(phone);
    if(idx < 0) {
        snprintf(err_msg, err_size, "账号不存在，请先注册");
        return -6;
    }
    
    // 5. 验证密码
    const AuthUser *user = get_user_by_index(idx);
    if(!user) {
        snprintf(err_msg, err_size, "系统错误");
        return -7;
    }
    if(strcmp(user->password, password) != 0) {
        snprintf(err_msg, err_size, "密码错误");
        return -8;
    }
    
    return 0;  // 验证通过
}

