void ui_event_Button1(lv_event_t * e)
{
    if(lv_event_get_code(e) == LV_EVENT_CLICKED) {
        if(keyboard_visible) {
            show_warning_message("请先关闭键盘", 1500);
            return;
        }
        
        const char *phone = lv_textarea_get_text(ui_TextArea1);
        const char *password = lv_textarea_get_text(ui_TextArea2);
        const char *code = lv_textarea_get_text(ui_TextArea_code);
        
        char err_msg[128];
        int result = validate_login_inputs(phone, password, code, err_msg, sizeof(err_msg));
        
        if(result == 0) {
            show_success_message("登录成功！", 1500);
            
            static ScreenChangeParams params;
            params.screen = &ui_Screen3;
            params.anim = LV_SCR_LOAD_ANIM_MOVE_LEFT;
            params.time = 500;
            params.delay = 0;
            
            lv_timer_t * timer = lv_timer_create(delayed_screen_change, 1500, &params);
            lv_timer_set_repeat_count(timer, 1);
        } else {
            show_error_message(err_msg, 2000);
        }
        
        // 无论登录成功还是失败，都刷新验证码
        generate_code();
    }
}

