// 打地鼠按钮事件
// 打地鼠按钮事件
void ui_event_whackamole(lv_event_t * e)
{
    if(lv_event_get_code(e) == LV_EVENT_CLICKED) {
        if(keyboard_visible) {
            show_warning_message("请先关闭键盘", 1500);
            return;
        }
        // 先销毁可能存在的旧 Screen7，确保每次都是全新游戏（与 Screen4 一致）
        if(ui_Screen7 != NULL) {
            ui_Screen7_screen_destroy();
        }
        _ui_screen_change(&ui_Screen7, LV_SCR_LOAD_ANIM_MOVE_LEFT, 500, 0, &ui_Screen7_screen_init);
    }
}

// ========== 屏幕销毁 ==========
void ui_Screen2_screen_destroy(void)
{
    if(popup_timer) {
        lv_timer_del(popup_timer);
        popup_timer = NULL;
    }
    if(popup_mask) {
        lv_obj_del(popup_mask);
        popup_mask = NULL;
    }
    if(popup_box) {
        lv_obj_del(popup_box);
        popup_box = NULL;
    }
    
    if(time_timer) {
        lv_timer_del(time_timer);
        time_timer = NULL;
    }
    time_label = NULL;
    
    if(ui_Screen2) lv_obj_del(ui_Screen2);
    ui_Screen2 = NULL;
    ui_Keyboard1 = NULL;
    ui_TextArea1 = NULL;
    ui_TextArea2 = NULL;
    ui_TextArea_code = NULL;
    ui_Label_code = NULL;
    ui_Button1 = NULL;
    ui_Label1 = NULL;
    ui_Label11 = NULL;
    ui_Label12 = NULL;
    ui_Button5 = NULL;
    ui_Button6 = NULL;
    ui_Label13 = NULL;
    ui_Label14 = NULL;
    ui_Button7 = NULL;
    ui_Label15 = NULL;
    pwd_visibility_btn = NULL;
    //pwd_visibility_label = NULL;
    
    keyboard_visible = 0;
    password_visible = 0;
    
    printf("[DEBUG] Screen2 destroyed\n");
}